export function t(lang, keyPath, params = {}) {
  const keys = keyPath.split('.');
  let val = keys.reduce((o, k) => o?.[k], translations[lang] || {});
  if (!val) val = keys.reduce((o, k) => o?.[k], translations.en || {});
  if (!val) return keyPath;
  Object.keys(params).forEach(k => { val = val.replace(`{${k}}`, params[k]); });
  return val;
}
